import React, { useState } from 'react';
import './FileUpload.css';

const FileUpload = () => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [uploadStatus, setUploadStatus] = useState('');
  const [isUploading, setIsUploading] = useState(false);

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    if (file && file.type === 'text/plain') {
      setSelectedFile(file);
      setUploadStatus('');
    } else {
      setSelectedFile(null);
      setUploadStatus('请选择.txt格式的文件');
    }
  };

  const handleUpload = async () => {
    if (!selectedFile) return;

    setIsUploading(true);
    setUploadStatus('');

    const formData = new FormData();
    formData.append('file', selectedFile);

    try {
      const response = await fetch('http://localhost:8000/api/upload', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();

      if (response.ok) {
        setUploadStatus(`上传成功: ${data.message}`);
        setSelectedFile(null);
        // 清空文件输入
        document.getElementById('file-input').value = '';
      } else {
        setUploadStatus(`上传失败: ${data.detail || '未知错误'}`);
      }
    } catch (error) {
      setUploadStatus('网络错误，请检查后端服务');
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="upload-container">
      <h2>复习资料上传</h2>
      <p>上传.txt格式的复习资料文件，用于构建您的个性化复习知识库。</p>

      <div className="upload-form">
        <input
          id="file-input"
          type="file"
          accept=".txt"
          onChange={handleFileSelect}
          disabled={isUploading}
        />

        {selectedFile && (
          <div className="file-info">
            <p><strong>文件名:</strong> {selectedFile.name}</p>
            <p><strong>大小:</strong> {(selectedFile.size / 1024).toFixed(2)} KB</p>
          </div>
        )}

        <button
          onClick={handleUpload}
          disabled={!selectedFile || isUploading}
          className="upload-button"
        >
          {isUploading ? '上传中...' : '上传到知识库'}
        </button>

        {uploadStatus && (
          <div className={`status-message ${uploadStatus.includes('成功') ? 'success' : 'error'}`}>
            {uploadStatus}
          </div>
        )}
      </div>
    </div>
  );
};

export default FileUpload;
